        let mut num = 0;
        for coronet_key in &heat.order {
            if let Some(pace) = heat.paces.get(coronet_key) {
                if let Some(tack) = pace.tacks.first() {
                    num += 1;
                    let state_str = zjjrpd_pace_state_str(&tack.state);
                    table.jjrp_write_row(&mut output, &[
                        &num.to_string(),
                        state_str,
                        &tack.silks,
                        coronet_key,
                    ]);
                }
            }
        }
    }
}

